	assert.Equal(t, want.TaskNumber, got.TaskNumber, "TaskNumber")
	assert.Equal(t, want.WaveNumber, got.WaveNumber, "WaveNumber")
	assert.Equal(t, want.PeerCount, got.PeerCount, "PeerCount")
